use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type PoolDatum {
  reserve_a: Int,
  reserve_b: Int,
  lp_supply: Int,
}

pub type WithdrawRedeemer {
  lp_burn_amount: Int,
  lp_policy_id: ByteArray,
  lp_asset_name: ByteArray,
  token_a_policy_id: ByteArray,
  token_a_asset_name: ByteArray,
  token_b_policy_id: ByteArray,
  token_b_asset_name: ByteArray,
  user_pkh: ByteArray,
}

fn get_pool_datum(input: Input) -> PoolDatum {
  when input.output.datum is {
    InlineDatum(raw) -> {
      expect typed: PoolDatum = raw
      typed
    }
    _ -> fail @"Pool input must have inline datum"
  }
}

fn find_user_output(
  outputs: List<Output>,
  user_pkh: ByteArray,
) -> Option<Output> {
  list.find(
    outputs,
    fn(o) {
      when o.address.payment_credential is {
        cardano/address.VerificationKey(pkh) -> pkh == user_pkh
        _ -> False
      }
    },
  )
}

fn proportional_amount(reserve: Int, lp_burn: Int, lp_supply: Int) -> Int {
  reserve * lp_burn / lp_supply
}

validator lp_withdraw {
  spend(
    datum: Option<PoolDatum>,
    redeemer: WithdrawRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(pool_datum) = datum

    let lp_burn_amount = redeemer.lp_burn_amount
    let lp_supply = pool_datum.lp_supply
    let reserve_a = pool_datum.reserve_a
    let reserve_b = pool_datum.reserve_b

    // LP burn amount must be positive
    let valid_burn_amount = lp_burn_amount > 0

    // LP supply must be positive
    let valid_lp_supply = lp_supply > 0

    // LP burn amount must not exceed supply
    let burn_not_exceed_supply = lp_burn_amount <= lp_supply

    // Calculate proportional shares
    let expected_a = proportional_amount(reserve_a, lp_burn_amount, lp_supply)
    let expected_b = proportional_amount(reserve_b, lp_burn_amount, lp_supply)

    // Verify LP tokens are burned in the mint field (negative quantity)
    let lp_minted =
      assets.quantity_of(self.mint, redeemer.lp_policy_id, redeemer.lp_asset_name)
    let valid_lp_burn = lp_minted == -lp_burn_amount

    // Find the continuing pool output (output that references current utxo's address)
    expect Some(pool_input) =
      list.find(self.inputs, fn(i) { i.output_reference == utxo })
    let pool_address = pool_input.output.address

    expect Some(pool_output) =
      list.find(self.outputs, fn(o) { o.address == pool_address })

    // Verify pool output has updated datum
    expect InlineDatum(raw_out) = pool_output.datum
    expect new_datum: PoolDatum = raw_out

    // Calculate new reserves after withdrawal
    let new_reserve_a = reserve_a - expected_a
    let new_reserve_b = reserve_b - expected_b
    let new_lp_supply = lp_supply - lp_burn_amount

    // Verify new datum reflects the withdrawal
    let valid_new_datum =
      new_datum.reserve_a == new_reserve_a && new_datum.reserve_b == new_reserve_b && new_datum.lp_supply == new_lp_supply

    // Verify pool output value decreased by the withdrawn amounts
    let pool_out_a =
      if redeemer.token_a_policy_id == #"" {
        assets.lovelace_of(pool_output.value)
      } else {
        assets.quantity_of(
          pool_output.value,
          redeemer.token_a_policy_id,
          redeemer.token_a_asset_name,
        )
      }

    let pool_in_a =
      if redeemer.token_a_policy_id == #"" {
        assets.lovelace_of(pool_input.output.value)
      } else {
        assets.quantity_of(
          pool_input.output.value,
          redeemer.token_a_policy_id,
          redeemer.token_a_asset_name,
        )
      }

    let pool_out_b =
      assets.quantity_of(
        pool_output.value,
        redeemer.token_b_policy_id,
        redeemer.token_b_asset_name,
      )

    let pool_in_b =
      assets.quantity_of(
        pool_input.output.value,
        redeemer.token_b_policy_id,
        redeemer.token_b_asset_name,
      )

    // Pool reserves decreased by exactly the withdrawn amounts
    let valid_pool_reserves_a = pool_in_a - pool_out_a == expected_a
    let valid_pool_reserves_b = pool_in_b - pool_out_b == expected_b

    valid_burn_amount && valid_lp_supply && burn_not_exceed_supply && valid_lp_burn && valid_new_datum && valid_pool_reserves_a && valid_pool_reserves_b
  }

  else(_) {
    fail
  }
}

