fn get_payment_key(output: Output) -> ByteArray {
  when output.address.payment_credential is {
    cardano/address.VerificationKey(vk) -> vk
    cardano/address.Script(sh) -> sh
  }
}

fn sum_lovelace_to_key(outputs: List<Output>, key: ByteArray) -> Int {
  list.foldl(
    outputs,
    0,
    fn(o, acc) {
      if get_payment_key(o) == key {
        acc + assets.lovelace_of(o.value)
      } else {
        acc
      }
    },
  )
}

fn get_input_lovelace(inputs: List<Input>, own_ref: OutputReference) -> Int {
  when list.find(inputs, fn(i) { i.output_reference == own_ref }) is {
    Some(i) -> assets.lovelace_of(i.output.value)
    None -> 0
  }
}

validator reward_split {
  spend(
    datum: Option<SplitDatum>,
    _redeemer: Data,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let total = get_input_lovelace(self.inputs, utxo)

    let expected_a = total * d.share_a_bps / 10000
    let expected_b = total * (10000 - d.share_a_bps) / 10000

    let actual_a = sum_lovelace_to_key(self.outputs, d.party_a)
    let actual_b = sum_lovelace_to_key(self.outputs, d.party_b)

    actual_a >= expected_a && actual_b >= expected_b
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
