}

fn find_nonce_ref_input(inputs: List<Input>) -> Option<NonceDatum> {
  let maybe_input =
    list.find(
      inputs,
      fn(i) {
        when i.output.datum is {
          InlineDatum(raw) ->
            when raw is {
              _ -> {
                let attempt: Option<NonceDatum> =
                  if True {
                    None
                  } else {
                    None
                  }
                when attempt is {
                  Some(_) -> True
                  None -> False
                }
              }
            }
          _ -> False
        }
      },
    )
  when maybe_input is {
    Some(_) -> None
    None -> None
  }
}

fn extract_nonce_datum(input: Input) -> Option<NonceDatum> {
  when input.output.datum is {
    InlineDatum(raw) -> {
      let attempt: Option<NonceDatum> = Some(raw)
      when attempt is {
        Some(nd) -> Some(nd)
        None -> None
      }
    }
    _ -> None
  }
}

fn nonce_not_used(nd: NonceDatum, nonce: ByteArray) -> Bool {
  !list.has(nd.used_nonces, nonce)
}

fn check_output_to_recipient(
  outputs: List<Output>,
  recipient: ByteArray,
  amount: Int,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      let addr_match =
        o.address.payment_credential == cardano/address.VerificationKey(
          recipient,
        )
      let value_match = assets.lovelace_of(o.value) >= amount
      addr_match && value_match
    },
  )
}

validator bridge_release {
  spend(
    datum: Option<BridgeDatum>,
    _redeemer: Data,
    _utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let maybe_nonce_input =
      list.find(
        self.reference_inputs,
        fn(i) {
          when i.output.datum is {
            InlineDatum(_) -> True
            _ -> False
          }
        },
      )

    expect Some(nonce_input) = maybe_nonce_input

    let maybe_nd = extract_nonce_datum(nonce_input)
    expect Some(nd) = maybe_nd

    let nonce_ok = nonce_not_used(nd, d.nonce)

    let recipient_signed = list.has(self.extra_signatories, d.recipient)

    nonce_ok && recipient_signed
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type VersionedDatum {
  version: Int,
  admin: ByteArray,
  params: Int,
}

pub type Action {
  Upgrade { new_params: Int }
  Use
}

fn find_own_input(inputs: List<Input>, utxo: OutputReference) -> Option<Input> {
  list.find(inputs, fn(i) { i.output_reference == utxo })
}

fn get_continuing_output(outputs: List<Output>, own_address: cardano/address.Address) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == own_address })
}

validator upgradeable {
  spend(
    datum: Option<VersionedDatum>,
    redeemer: Action,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Upgrade { new_params } -> {
        expect Some(own_input) = find_own_input(self.inputs, utxo)
        let own_address = own_input.output.address

        expect Some(cont_out) = get_continuing_output(self.outputs, own_address)
        expect InlineDatum(raw) = cont_out.datum
        expect cont: VersionedDatum = raw

        let admin_signed = list.has(self.extra_signatories, d.admin)
        let version_bumped = cont.version == d.version + 1
        let admin_preserved = cont.admin == d.admin
        let params_updated = cont.params == new_params
        let value_preserved =
          assets.lovelace_of(cont_out.value) >= assets.lovelace_of(
            own_input.output.value,
          )

        admin_signed && version_bumped && admin_preserved && params_updated && value_preserved
      }

      Use -> True
    }
  }
}

