  token_policy: ByteArray,
  token_name: ByteArray,
  price: Int,
}

pub type SaleRedeemer {
  Buy
  Cancel
}

fn seller_receives_price(outputs: List<Output>, seller: ByteArray, price: Int) -> Bool {
  let seller_addr_hash = seller
  list.any(
    outputs,
    fn(o) {
      when o.address.payment_credential is {
        cardano/address.VerificationKey(pkh) ->
          pkh == seller_addr_hash && assets.lovelace_of(o.value) >= price
        _ -> False
      }
    },
  )
}

fn buyer_receives_token(
  outputs: List<Output>,
  seller: ByteArray,
  token_policy: ByteArray,
  token_name: ByteArray,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      let not_seller =
        when o.address.payment_credential is {
          cardano/address.VerificationKey(pkh) -> pkh != seller
          _ -> True
        }
      let has_token = assets.quantity_of(o.value, token_policy, token_name) == 1
      not_seller && has_token
    },
  )
}

validator token_sale {
  spend(
    datum: Option<SaleDatum>,
    redeemer: SaleRedeemer,
    _utxo: cardano/transaction.OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    when redeemer is {
      Buy -> {
        let seller_paid =
          seller_receives_price(self.outputs, d.seller, d.price)
        let buyer_has_token =
          buyer_receives_token(
            self.outputs,
            d.seller,
            d.token_policy,
            d.token_name,
          )
        seller_paid && buyer_has_token
      }
      Cancel -> list.has(self.extra_signatories, d.seller)
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type FundDatum {
  goal: Int,
  deadline: Int,
  creator: ByteArray,
}

pub type FundRedeemer {
  Withdraw
  Refund
}

fn total_lovelace_at_script(inputs: List<Input>, script_address: cardano/address.Address) -> Int {
  list.foldl(
    inputs,
    0,
    fn(input, acc) {
      if input.output.address == script_address {
        acc + assets.lovelace_of(input.output.value)
      } else {
        acc
      }
    },
  )
}

validator crowdfund {
  spend(
    datum: Option<FundDatum>,
    redeemer: FundRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Withdraw -> {
        let is_after_deadline =
          interval.is_entirely_after(self.validity_range, d.deadline)

        let is_signed_by_creator =
          list.has(self.extra_signatories, d.creator)

        expect Some(own_input) =
          list.find(self.inputs, fn(i) { i.output_reference == utxo })

        let own_address = own_input.output.address

        let total_funds =
          total_lovelace_at_script(self.inputs, own_address)

        let goal_met = total_funds >= d.goal

        is_after_deadline && is_signed_by_creator && goal_met
      }

      Refund -> {
        let is_after_deadline =
          interval.is_entirely_after(self.validity_range, d.deadline)

        expect Some(own_input) =
          list.find(self.inputs, fn(i) { i.output_reference == utxo })

        let own_address = own_input.output.address

        let total_funds =
          total_lovelace_at_script(self.inputs, own_address)

        let goal_not_met = total_funds < d.goal

        is_after_deadline && goal_not_met
      }
    }
  }
}

use aiken/collection/list
use cardano/assets
use cardano/transaction.{InlineDatum, Output, Transaction}

pub type VaultDatum {
  owner: ByteArray,
  min_tokens: Int,
}

fn count_policy_tokens(outputs: List<Output>, policy_id: ByteArray) -> Int {
  list.foldl(
    outputs,
    0,
    fn(output, acc) {
      let tokens = assets.tokens(output.value, policy_id)
      let token_sum =
        list.foldl(
          tokens |> dict_to_list,
          0,
          fn(pair, inner_acc) {
            let (_, qty) = pair
            inner_acc + qty
          },
        )
      acc + token_sum
    },
  )
}

fn dict_to_list(d: aiken/collection/dict.Dict<ByteArray, Int>) -> List<(ByteArray, Int)> {
  aiken/collection/dict.to_pairs(d)
    |> list.map(fn(pair) { (pair.1st, pair.2nd) })
}

validator parametric_vault(policy_id: ByteArray) {
  spend(
    datum: Option<VaultDatum>,
    _redeemer: Data,
    _utxo: cardano/transaction.OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    let owner_signed = list.has(self.extra_signatories, d.owner)

    let total_tokens = count_policy_tokens(self.outputs, policy_id)

    let enough_tokens = total_tokens >= d.min_tokens

    owner_signed && enough_tokens
  }

  else(_) {
    fail
  }
}

use aiken/collection/list
use cardano/assets
use cardano/transaction.{InlineDatum, Output, Transaction}
use cardano/address.{Address}

pub type BatchDatum {
  recipients: List<ByteArray>,
  amounts: List<Int>,
  sender: ByteArray,
}

fn zip_recipients_amounts(
  recipients: List<ByteArray>,
  amounts: List<Int>,
) -> List<(ByteArray, Int)> {
  when recipients is {
    [] -> []
    [r, ..rest_r] ->
      when amounts is {
        [] -> []
        [a, ..rest_a] -> [(r, a), ..zip_recipients_amounts(rest_r, rest_a)]
      }
  }
}

fn address_payment_credential_matches(
  addr: Address,
  recipient: ByteArray,
) -> Bool {
  when addr.payment_credential is {
    cardano/address.VerificationKey(pkh) -> pkh == recipient
    _ -> False
  }
}

fn output_satisfies_pair(
  outputs: List<Output>,
  recipient: ByteArray,
  amount: Int,
) -> Bool {
  list.any(
    outputs,
    fn(o) {
      address_payment_credential_matches(o.address, recipient) && assets.lovelace_of(
        o.value,
      ) >= amount
    },
  )
}

fn all_pairs_satisfied(
  pairs: List<(ByteArray, Int)>,
  outputs: List<Output>,
) -> Bool {
  list.foldl(
    pairs,
    True,
    fn(pair, acc) {
      let (recipient, amount) = pair
      acc && output_satisfies_pair(outputs, recipient, amount)
    },
  )
}

validator batch_transfer {
  spend(
    datum: Option<BatchDatum>,
    _redeemer: Data,
    _utxo: cardano/transaction.OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let sender_signed = list.has(self.extra_signatories, d.sender)
    let pairs = zip_recipients_amounts(d.recipients, d.amounts)
    let has_pairs = !list.is_empty(pairs)
    let all_satisfied = all_pairs_satisfied(pairs, self.outputs)
    sender_signed && has_pairs && all_satisfied
  }
}

use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{InlineDatum, Input, Output, OutputReference, Transaction}

pub type RecurringDatum {
  payer: ByteArray,
  payee: ByteArray,
  amount: Int,
  period_secs: Int,
  last_paid: Int,
}

pub type RecurringRedeemer {
  Pay
  Cancel
}

fn find_output_to_address(
  outputs: List<Output>,
  addr: cardano/address.Address,
) -> Option<Output> {
  list.find(outputs, fn(o) { o.address == addr })
}

validator recurring_payment {
  spend(
    datum: Option<RecurringDatum>,
    redeemer: RecurringRedeemer,
    utxo: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum

    when redeemer is {
      Cancel -> list.has(self.extra_signatories, d.payer)
      Pay -> {
        let deadline = d.last_paid + d.period_secs

        let period_elapsed =
          interval.is_entirely_after(self.validity_range, deadline)

        let payee_receives_enough =
          list.any(
            self.outputs,
            fn(o) {
              let payee_addr_matches =
                when o.datum is {
                  _ -> True
                }
              let _ = payee_addr_matches
              assets.lovelace_of(o.value) >= d.amount && list.has(
                self.extra_signatories,
                d.payee,
              ) || assets.lovelace_of(o.value) >= d.amount
            },
          )

        let payer_signed = list.has(self.extra_signatories, d.payer)

        let continuing_output_valid =
          list.any(
            self.outputs,
            fn(o) {
              when o.datum is {
                InlineDatum(raw) -> {
                  expect next: RecurringDatum = raw
                  next.payer == d.payer && next.payee == d.payee && next.amount == d.amount && next.period_secs == d.period_secs && next.last_paid > d.last_paid
                }
                _ -> False
              }
            },
          )

        period_elapsed && payer_signed && payee_receives_enough && continuing_output_valid
      }
    }
  }

  else(_) {
    fail
  }
}
